// Pass-through summary node. Lets the n8n UI show how many
// rows were dispatched on the last tick without breaking the
// flow. If the Edge Function returned non-ok, surface that as a
// thrown error so the workflow shows red in the n8n UI.
const body = $input.first().json;
if (body && body.ok === false) {
  throw new Error(`social-dispatcher returned not-ok: ${JSON.stringify(body).slice(0, 256)}`);
}
return [{ json: { tick: new Date().toISOString(), dispatched: body?.dispatched ?? 0, results: body?.results ?? [] } }];
